-- Common CODO rules catalog (global, shared across projects)
CREATE TABLE IF NOT EXISTS `codo_common_rules` (
  `id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `phase` ENUM('developer','tester','project') NOT NULL,
  `rule_key` VARCHAR(64) NOT NULL,
  `title` VARCHAR(255) NOT NULL,
  `subtitle` VARCHAR(255) NULL DEFAULT NULL,
  `description` TEXT NOT NULL,
  `sort_order` INT NOT NULL DEFAULT 0,
  `is_active` TINYINT(1) NOT NULL DEFAULT 1,
  `created_by` VARCHAR(36) NULL DEFAULT NULL,
  `updated_by` VARCHAR(36) NULL DEFAULT NULL,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_codo_common_phase_key` (`phase`, `rule_key`),
  KEY `idx_codo_common_phase_active` (`phase`, `is_active`),
  KEY `idx_codo_common_sort` (`phase`, `sort_order`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

